@namespace Lumeo
@implements IAsyncDisposable

@if (Open && _currentStepConfig is not null)
{
    <!-- Spotlight overlay -->
    <div class="fixed inset-0 z-[60]" aria-hidden="true" @onclick="HandleOverlayClick">
        <svg class="absolute inset-0 w-full h-full" style="pointer-events: none;">
            <defs>
                <mask id="@_maskId">
                    <rect x="0" y="0" width="100%" height="100%" fill="white" />
                    @if (_targetRect is not null)
                    {
                        <rect x="@(_targetRect.X - 4)" y="@(_targetRect.Y - 4)"
                              width="@(_targetRect.Width + 8)" height="@(_targetRect.Height + 8)"
                              rx="@SpotlightRadius" ry="@SpotlightRadius" fill="black" />
                    }
                </mask>
            </defs>
            <rect x="0" y="0" width="100%" height="100%" fill="var(--color-overlay-backdrop)"
                  mask="url(#@_maskId)" style="pointer-events: all;" />
        </svg>

        @if (_targetRect is not null)
        {
            <!-- Highlight ring around target — border-radius matches the target's computed radius + the 4px spotlight padding. -->
            <div class="absolute ring-2 ring-primary" style="pointer-events: none;
                left: @(_targetRect.X - 4)px; top: @(_targetRect.Y - 4)px;
                width: @(_targetRect.Width + 8)px; height: @(_targetRect.Height + 8)px;
                border-radius: @(SpotlightRadius)px;" />
        }
    </div>

    <!-- Tooltip -->
    <div id="@_tooltipId" class="@TooltipCssClass" style="@TooltipStyle" role="dialog" aria-modal="true" tabindex="-1" aria-label="@(_currentStepConfig.Title ?? $"Tour step {CurrentStep + 1}")" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
        <div class="flex flex-col gap-2">
            @if (!string.IsNullOrEmpty(_currentStepConfig.Title))
            {
                <h4 class="text-sm font-semibold text-foreground">@_currentStepConfig.Title</h4>
            }
            @if (!string.IsNullOrEmpty(_currentStepConfig.Description))
            {
                <p class="text-sm text-muted-foreground">@_currentStepConfig.Description</p>
            }

            <div class="flex items-center justify-between pt-2">
                <span class="text-xs text-muted-foreground">@(CurrentStep + 1) / @Steps.Count</span>
                <div class="flex items-center gap-2">
                    <button type="button" class="inline-flex items-center justify-center rounded-md text-xs font-medium h-7 px-2
                                   text-muted-foreground hover:text-foreground transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                            @onclick="HandleSkip">
                        @L["Tour.Skip"]
                    </button>
                    @if (CurrentStep > 0)
                    {
                        <button type="button" class="inline-flex items-center justify-center rounded-md text-xs font-medium h-7 px-3
                                       border border-border/60 bg-background text-foreground hover:bg-accent transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                                @onclick="HandlePrevious">
                            @L["Tour.Previous"]
                        </button>
                    }
                    @if (CurrentStep < Steps.Count - 1)
                    {
                        <button type="button" class="inline-flex items-center justify-center rounded-md text-xs font-medium h-7 px-3
                                       bg-primary text-primary-foreground hover:bg-primary/90 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                                @onclick="HandleNext">
                            @L["Tour.Next"]
                        </button>
                    }
                    else
                    {
                        <button type="button" class="inline-flex items-center justify-center rounded-md text-xs font-medium h-7 px-3
                                       bg-primary text-primary-foreground hover:bg-primary/90 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                                @onclick="HandleComplete">
                            @L["Tour.Finish"]
                        </button>
                    }
                </div>
            </div>
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    /// <summary>The ordered sequence of tour steps, each targeting an element by CSS
    /// selector with its own title/description/placement.</summary>
    [Parameter] public List<TourStepConfig> Steps { get; set; } = [];
    /// <summary>Whether the tour overlay + tooltip are shown. Set to <c>true</c> to start
    /// the tour; the component sets it back to <c>false</c> internally on skip/complete.</summary>
    [Parameter] public bool Open { get; set; }
    /// <summary>Fired when the tour opens or closes (including internal skip/complete/Escape).
    /// Bind alongside <see cref="Open"/> to control it.</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>Deprecated alias for <see cref="Open"/>.</summary>
    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    /// <summary>Deprecated alias for <see cref="OpenChanged"/>.</summary>
    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    /// <summary>Zero-based index into <see cref="Steps"/> of the currently displayed step.</summary>
    [Parameter] public int CurrentStep { get; set; }
    /// <summary>Fired when the current step changes via Next/Previous, an arrow key, or
    /// <see cref="Close"/> resetting it to 0. Bind alongside <see cref="CurrentStep"/>
    /// to control it.</summary>
    [Parameter] public EventCallback<int> CurrentStepChanged { get; set; }
    /// <summary>Fired when the user finishes the last step ("Finish" button).</summary>
    [Parameter] public EventCallback OnComplete { get; set; }
    /// <summary>Fired when the user skips the tour (Skip button, overlay click, or Escape).</summary>
    [Parameter] public EventCallback OnSkip { get; set; }
    /// <summary>Additional CSS classes merged onto the step tooltip.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the step tooltip.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _tooltipId = LumeoIds.New("tour-tooltip");
    private readonly string _maskId = LumeoIds.New("tour-mask");
    private ElementRect? _targetRect;
    private TourStepConfig? _currentStepConfig;
    private bool _scrollLocked;
    private string? _currentTargetSelector;
    // Step we last moved focus into, so we focus once per step (not every render).
    private int _focusedStep = -1;

    private string TooltipCssClass => Cx.Merge("fixed z-[61] w-80 rounded-lg border border-border/60 bg-popover p-4 text-popover-foreground shadow-lg animate-fade-in", Class);

    // Spotlight padding (4 px all sides), plus the target's own border-radius, so the mask + ring wrap the target
    // with the same corner curve they would have if you'd drawn them directly on top.
    private string SpotlightRadius => ((_targetRect?.BorderRadius ?? 0) + 4).ToString("F2", System.Globalization.CultureInfo.InvariantCulture);

    private string TooltipStyle
    {
        get
        {
            if (_targetRect is null) return "left: 50%; top: 50%; transform: translate(-50%, -50%);";
            var placement = _currentStepConfig?.Placement ?? Lumeo.Side.Bottom;
            return placement switch
            {
                Lumeo.Side.Top => $"left: {_targetRect.X + _targetRect.Width / 2}px; top: {_targetRect.Y - 12}px; transform: translateX(-50%) translateY(-100%);",
                Lumeo.Side.Bottom => $"left: {_targetRect.X + _targetRect.Width / 2}px; top: {_targetRect.Y + _targetRect.Height + 12}px; transform: translateX(-50%);",
                Lumeo.Side.Left => $"left: {_targetRect.X - 12}px; top: {_targetRect.Y + _targetRect.Height / 2}px; transform: translateX(-100%) translateY(-50%);",
                Lumeo.Side.Right => $"left: {_targetRect.X + _targetRect.Width + 12}px; top: {_targetRect.Y + _targetRect.Height / 2}px; transform: translateY(-50%);",
                _ => $"left: {_targetRect.X + _targetRect.Width / 2}px; top: {_targetRect.Y + _targetRect.Height + 12}px; transform: translateX(-50%);"
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        if (Open && Steps.Count > 0 && CurrentStep >= 0 && CurrentStep < Steps.Count)
        {
            _currentStepConfig = Steps[CurrentStep];
        }
        else
        {
            // Whenever the step dialog is NOT rendered (Steps emptied during an
            // async load flicker, or the parent set Open=false externally without
            // going through Close()), drop the per-step UI state so a later
            // refill / reopen re-establishes it from scratch:
            //   • _focusedStep   — else focus is never moved back into the dialog
            //     when it remounts at the SAME step (keyboard user stranded).
            //   • _currentTargetSelector / _targetRect — else UpdateTargetRect
            //     early-returns (selector unchanged) on reopen and the spotlight
            //     points at a stale rect.
            // This mirrors the reset that Close() already performs, so a
            // parent-driven dismiss behaves symmetrically with the internal close.
            _currentStepConfig = null;
            _focusedStep = -1;
            _currentTargetSelector = null;
            _targetRect = null;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Open && _currentStepConfig is not null)
        {
            // Off-screen step targets must be scrolled into view BEFORE the
            // body lock — a locked body can't be scrolled at all, so the
            // spotlight pointed at nothing and the user couldn't reach it.
            // On step changes the lock is briefly lifted for the same reason
            // (LockScroll is ref-counted; the cycle is invisible).
            var movingToNewTarget = _currentStepConfig?.TargetSelector is not null
                && _currentStepConfig?.TargetSelector != _currentTargetSelector;
            if (movingToNewTarget && _scrollLocked)
            {
                try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
                _scrollLocked = false;
            }
            if (!_scrollLocked)
            {
                if (movingToNewTarget && _currentStepConfig?.TargetSelector is { } sel)
                {
                    try { await Interop.ScrollSelectorIntoView(sel); }
                    catch (JSDisconnectedException) { }
                }
                await Interop.LockScroll();
                _scrollLocked = true;
            }
            await UpdateTargetRect();

            // Move focus into the step dialog on each new step so keyboard users
            // aren't stranded behind the overlay and the @onkeydown handler
            // (Escape / arrow navigation) receives events. Focus once per step.
            if (_focusedStep != CurrentStep)
            {
                _focusedStep = CurrentStep;
                try { await Interop.FocusElement(_tooltipId); } catch (JSDisconnectedException) { }
            }
        }
        else if (_scrollLocked)
        {
            try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
            _scrollLocked = false;
        }
    }

    // Sequence stamp for UpdateTargetRect calls. Bumped on every entry;
    // the awaited fetch checks the stamp on resolve to drop stale results.
    private int _rectFetchSeq;

    private async Task UpdateTargetRect()
    {
        var selector = _currentStepConfig?.TargetSelector;
        if (selector == _currentTargetSelector) return; // Already positioned for this step
        _currentTargetSelector = selector;
        // Race fix: if a second UpdateTargetRect fires while this call is
        // awaiting GetElementRectBySelector (parent advances CurrentStep
        // mid-flight, or HandleNext / HandlePrevious overlap), the later
        // call bumps _rectFetchSeq and wins. Without this guard the
        // earlier resolution overwrote _targetRect with the previous
        // step's rect AFTER the later call had already committed the
        // right rect — spotlight stuck on the wrong target for a render.
        var stamp = ++_rectFetchSeq;
        var newRect = selector is not null
            ? await Interop.GetElementRectBySelector(selector)
            : null;
        if (stamp != _rectFetchSeq) return; // Newer call already committed.
        _targetRect = newRect;
        StateHasChanged();
    }

    private async Task HandleNext()
    {
        if (CurrentStep < Steps.Count - 1)
        {
            CurrentStep++;
            _currentStepConfig = Steps[CurrentStep];
            _currentTargetSelector = null; // Force re-fetch for new step
            await CurrentStepChanged.InvokeAsync(CurrentStep);
            // Do NOT pre-fetch the rect here. Resetting _currentTargetSelector to
            // null lets OnAfterRenderAsync own the full move sequence
            // (scroll-into-view → LockScroll → UpdateTargetRect). Calling
            // UpdateTargetRect() here would set _currentTargetSelector to the new
            // step's selector before the render, making movingToNewTarget false,
            // so an off-screen target was never scrolled into view on Next/Previous.
        }
    }

    private async Task HandlePrevious()
    {
        if (CurrentStep > 0)
        {
            CurrentStep--;
            _currentStepConfig = Steps[CurrentStep];
            _currentTargetSelector = null; // Force re-fetch for new step
            await CurrentStepChanged.InvokeAsync(CurrentStep);
            // See HandleNext: OnAfterRenderAsync is the single owner of the
            // scroll-into-view + lock + UpdateTargetRect sequence.
        }
    }

    private async Task HandleSkip()
    {
        await Close();
        await OnSkip.InvokeAsync();
    }

    private async Task HandleComplete()
    {
        await Close();
        await OnComplete.InvokeAsync();
    }

    private async Task HandleOverlayClick()
    {
        // Click on overlay (outside target) - skip tour
        await HandleSkip();
    }

    // Keyboard model matching driver.js / intro.js: Escape skips the tour, the
    // arrow keys move between steps. The step dialog is focused on each step so
    // these events reach this handler.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await HandleSkip();
                break;
            case "ArrowRight":
                if (CurrentStep < Steps.Count - 1) await HandleNext();
                break;
            case "ArrowLeft":
                if (CurrentStep > 0) await HandlePrevious();
                break;
        }
    }

    private async Task Close()
    {
        Open = false;
        CurrentStep = 0;
        _currentStepConfig = null;
        _targetRect = null;
        _currentTargetSelector = null;
        _focusedStep = -1;
        await OpenChanged.InvokeAsync(false);
        await CurrentStepChanged.InvokeAsync(0);
        if (_scrollLocked)
        {
            try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
            _scrollLocked = false;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_scrollLocked)
        {
            try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
        }
    }

    public record TourStepConfig(string? TargetSelector, string Title, string? Description = null, Lumeo.Side Placement = Lumeo.Side.Bottom);

}
